            }

            long remaining = maxBytes - bytesRead;
            int toRead = (int) Math.min(len, remaining);

            int result = delegate.read(b, off, toRead);
            if (result > 0) {
                bytesRead += result;
            }
            return result;
        }

        @Override
        public void close() throws IOException {
            delegate.close();
        }
    }
