    private boolean isValidAndSafeUrl(String urlString) {
        if (urlString == null || urlString.trim().isEmpty()) {
            return false;
        }

        try {
            URI uri = new URI(urlString);
            String scheme = uri.getScheme();
            String host = uri.getHost();

            // Check scheme
            if (scheme == null || !ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
                System.err.println("Scheme not allowed: " + scheme);
                return false;
            }

            // Check host exists
            if (host == null || host.trim().isEmpty()) {
                System.err.println("Host is missing");
                return false;
            }

            // Normalize host
            host = host.toLowerCase();

            // Check against blocked hosts
            if (BLOCKED_HOSTS.contains(host)) {
                System.err.println("Host is blocked: " + host);
                return false;
            }

            // Resolve IP address and check if it's private
            InetAddress inetAddress = InetAddress.getByName(host);
            if (isPrivateOrLocalAddress(inetAddress)) {
                System.err.println("Private or local IP address not allowed: " + 
                    inetAddress.getHostAddress());
                return false;
            }

            // Check for suspicious patterns
            if (host.matches(".*\\d+\\.\\d+\\.\\d+\\.\\d+.*") && 
                (host.startsWith("10.") || host.startsWith("192.168.") || 
                 host.matches("172\\.(1[6-9]|2[0-9]|3[0-1])\\..*"))) {
                System.err.println("Private IP range detected: " + host);
                return false;
            }

            return true;

        } catch (URISyntaxException e) {
            System.err.println("Invalid URI syntax: " + e.getMessage());
            return false;
        } catch (UnknownHostException e) {
            System.err.println("Unknown host: " + e.getMessage());
            return false;
        } catch (Exception e) {
            System.err.println("Error validating URL: " + e.getMessage());
            return false;
        }
    }

    private boolean isPrivateOrLocalAddress(InetAddress address) {
        return address.isLoopbackAddress() || 
               address.isLinkLocalAddress() || 
               address.isSiteLocalAddress() ||
               address.isAnyLocalAddress();
    }
